AdditionHelper = {}

function AdditionHelper:additionEject(target, additionIds)
    for _, additionId in pairs(additionIds) do
        local config = AdditionConfig:getConfigById(tonumber(additionId))
        if config then
            target.properties[config.propertyName] = target.properties[config.propertyName] + config.toneUp
        end
    end
    target:checkPropertyChange()
end